type VocabularyMatcher struct {
	matchMode string
	minLen    int
	lookup    map[string]lookupVal
	entities  map[string]entityMeta
}

type EntityDef struct {
	ID          string
	Name        string
	DisplayName string
	Type        string
	EntityType  string
	Aliases     []string
}

func NewVocabularyMatcher(entities []EntityDef, matchMode string, minEntityLength int) (*VocabularyMatcher, error) {
	vm := &VocabularyMatcher{
		matchMode: matchMode,
		minLen:    minEntityLength,
		lookup:    make(map[string]lookupVal),
		entities:  make(map[string]entityMeta),
	}
	for _, ent := range entities {
		eid := ent.ID
		dtype := ent.Type
		if dtype == "" {
			dtype = ent.EntityType
		}
		if dtype == "" {
			dtype = "concept"
		}
		vm.entities[eid] = entityMeta{
			id:          eid,
			name:        ent.Name,
			displayName: ent.DisplayName,
			entityType:  dtype,
		}
		surfaces := append([]string{ent.Name, ent.DisplayName}, ent.Aliases...)
		for _, surface := range surfaces {
			if len(surface) < vm.minLen {
				continue
			}
			key := surface
			if matchMode != "exact" {
				key = strings.ToLower(surface)
			}
			vm.lookup[key] = lookupVal{entityID: eid, displayName: ent.DisplayName, entityType: dtype}
		}
	}
	return vm, nil
}

import (
	"regexp"
	"strings"
)

var (
	camelRE   = regexp.MustCompile(`([a-z])([A-Z])`)
	pascalRE  = regexp.MustCompile(`([A-Z]+)([A-Z][a-z])`)
	autoIDRE  = regexp.MustCompile(`[^a-z0-9]+`)
)

func normalizeSchemaTermFull(term string, toSingular bool) string {
	s := camelRE.ReplaceAllString(term, "${1} ${2}")
	s = pascalRE.ReplaceAllString(s, "${1} ${2}")
	s = strings.ReplaceAll(s, "_", " ")
	s = strings.ReplaceAll(s, "-", " ")
	s = strings.Join(strings.Fields(s), " ")
	s = strings.ToLower(s)
	if toSingular && strings.HasSuffix(s, "s") {
		s = s[:len(s)-1]
	}
	return s
}

func normalizeSchemaTerm(term string) string {
	return normalizeSchemaTermFull(term, false)
}

func autoID(displayName string) string {
	lower := strings.ToLower(displayName)
	s := autoIDRE.ReplaceAllString(lower, "_")
	return strings.Trim(s, "_")
}

