func extractSQLTerms(sql string) (tables []string, columns []string) {
	seen := make(map[string]bool)
	for _, m := range createTableRE.FindAllStringSubmatchIndex(sql, -1) {
		name := sql[m[2]:m[3]]
		tables = append(tables, name)
		seen[name] = true
	}
	for _, m := range alterTableRE.FindAllStringSubmatchIndex(sql, -1) {
		name := sql[m[2]:m[3]]
		if !seen[name] {
			tables = append(tables, name)
			seen[name] = true
		}
	}
	for _, m := range colRE.FindAllStringSubmatchIndex(sql, -1) {
		start := m[0]
		nl := strings.Index(sql[start:], "\n")
		var line string
		if nl < 0 {
			line = sql[start:]
		} else {
			line = sql[start : start+nl]
		}
		if skipStartsRE.MatchString(line) {
			continue
		}
		columns = append(columns, sql[m[2]:m[3]])
	}
	return tables, columns
}

func (b *SchemaVocabBuilder) AddSQL(ddl string) *SchemaVocabBuilder {
	tables, columns := extractSQLTerms(ddl)
	for _, t := range tables {
		if len(t) >= b.min {
			b.tables[t] = struct{}{}
		}
	}
	for _, c := range columns {
		if len(c) >= b.min {
			b.columns[c] = struct{}{}
		}
	}
	return b
}

