func (b *SchemaVocabBuilder) AddChunks(chunks []DocumentChunk) *SchemaVocabBuilder {
	for _, chunk := range chunks {
		docName := chunk.DocumentName
		chunkType := chunk.ChunkType

		if (chunkType == "db_table" || chunkType == "db_column") && strings.HasPrefix(docName, "schema:") {
			inner := docName[len("schema:"):]
			parts := strings.Split(inner, ".")
			if len(parts) >= 2 {
				table := parts[1]
				if len(table) >= b.min {
					b.tables[table] = struct{}{}
				}
			}
			if len(parts) >= 3 {
				col := parts[2]
				if len(col) >= b.min {
					b.columns[col] = struct{}{}
				}
			}
		} else if chunkType == "api_endpoint" || chunkType == "api_graphql_query" ||
			chunkType == "api_graphql_mutation" || chunkType == "api_graphql_type" {
			if strings.HasPrefix(docName, "api:") {
				inner := docName[len("api:"):]
				parts := strings.SplitN(inner, ".", 2)
				if len(parts) >= 2 {
					path := parts[1]
					if len(path) >= b.min {
