			inner := docName[len("api:"):]
			parts := strings.Split(inner, ".")
			if len(parts) >= 3 {
				field := parts[len(parts)-1]
				if len(field) >= b.min {
					b.columns[field] = struct{}{}
				}
			}
		}
	}
	return b
