// DBConnection is any object supporting Execute and optionally Close.
type DBConnection interface {
	Execute(sql string) ([]string, error)
	Close() error
}

func (b *SchemaVocabBuilder) AddFromDB(conn DBConnection, pairs []QueryPair, rowLimit int) (*SchemaVocabBuilder, error) {
	if rowLimit <= 0 {
		rowLimit = 10000
	}
	defer conn.Close()
	for _, p := range pairs {
		limited := fmt.Sprintf("SELECT * FROM (%s) _q LIMIT %d", p.SQL, rowLimit)
		values, err := conn.Execute(limited)
		if err != nil {
			return nil, fmt.Errorf("add_from_db execute: %w", err)
		}
		for _, val := range values {
			if len(val) >= b.min {
				b.dataTerms = append(b.dataTerms, DataTerm{Name: val, EntityType: p.EntityType})
			}
		}
	}
	return b, nil
}

