// Connector is implemented by SQLAlchemy Engine equivalents that have Connect() but not Execute().
type Connector interface {
	Connect() (Executor, error)
}

// Executor is a live DB connection with an Execute method.
type Executor interface {
	Execute(sql string) ([][]interface{}, error)
	Close() error
}

// ConnOrConnector is the union accepted by resolveConnection.
type ConnOrConnector interface{}

func resolveConnection(connection ConnOrConnector) (Executor, error) {
	switch c := connection.(type) {
	case string:
		engine, err := openSQLAlchemyEngine(c)
		if err != nil {
			return nil, fmt.Errorf("resolveConnection: open engine: %w", err)
		}
		return engine.Connect()
	case Connector:
		return c.Connect()
	case Executor:
		return c, nil
	default:
		return nil, fmt.Errorf("add_from_db() connection must be a URL string, Connector, or Executor; got %T", connection)
	}
}

