func executeQuery(conn Executor, sql string) ([]string, error) {
	rows, err := conn.Execute(sql)
	if err != nil {
		return nil, fmt.Errorf("executeQuery: %w", err)
	}
	if len(rows) == 0 {
		return nil, nil
	}
	// Validate single column
	if len(rows[0]) != 1 {
		return nil, fmt.Errorf("add_from_db() queries must return exactly one column (got %d). SQL: %q", len(rows[0]), sql)
	}
	seen := make(map[string]struct{})
	var values []string
	for _, row := range rows {
		val := row[0]
		if val == nil {
			continue
		}
		s := strings.TrimSpace(fmt.Sprintf("%v", val))
		if len(s) > 0 {
			if _, exists := seen[s]; !exists {
				seen[s] = struct{}{}
				values = append(values, s)
			}
		}
	}
	return values, nil
}

