// maybeClose closes conn only when original was a URL string or a Connector
// (Engine-like object). If original was already an Executor, we do not close it.
func maybeClose(conn Executor, original ConnOrConnector) {
	switch original.(type) {
	case string:
		// We opened it from a URL — close it.
		_ = conn.Close()
	case Connector:
		// We called Connect() on an engine — close the connection we obtained.
		_ = conn.Close()
	// case Executor: caller already owned it, do not close.
	}
}

