type schemaLookupVal struct {
	entityID    string
	displayName string
	entityType  string
}

type schemaEntityMeta struct {
	canonical   string
	displayName string
	entityType  string
}

type SchemaMatcher struct {
	lookup   map[string]schemaLookupVal
	entities map[string]schemaEntityMeta
}

func NewSchemaMatcher(schemaTerms []string, apiTerms []string, businessTerms []string) *SchemaMatcher {
	sm := &SchemaMatcher{
		lookup:   make(map[string]schemaLookupVal),
		entities: make(map[string]schemaEntityMeta),
	}
	type termGroup struct {
		terms []string
		etype string
	}
	groups := []termGroup{
		{terms: schemaTerms, etype: "schema"},
		{terms: apiTerms, etype: "api"},
		{terms: businessTerms, etype: "term"},
	}
	for _, g := range groups {
		for _, term := range g.terms {
			canonical := normalizeSchemaTermFull(term, true)
			eid := autoID(canonical)
			sm.entities[eid] = schemaEntityMeta{canonical: canonical, displayName: term, entityType: g.etype}
			for _, variant := range variants(term) {
				if _, exists := sm.lookup[variant]; !exists {
					sm.lookup[variant] = schemaLookupVal{entityID: eid, displayName: term, entityType: g.etype}
				}
			}
		}
	}
	return sm
}

